-- ----------------------------
-- Table structure for ai_command_record
-- ----------------------------
DROP TABLE IF EXISTS `ai_command_record`;
CREATE TABLE `ai_command_record`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `user_id` bigint NULL DEFAULT NULL COMMENT '用户ID',
  `username` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '用户名',
  `original_command` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '原始命令',
  `provider` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'AI供应商(qwen/openai/deepseek/gemini等)',
  `model` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'AI模型(qwen-plus/qwen-max/gpt-4-turbo等)',
  `parse_success` tinyint(1) NULL DEFAULT NULL COMMENT '解析是否成功(0-失败, 1-成功)',
  `function_calls` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '解析出的函数调用列表(JSON)',
  `explanation` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'AI的理解说明',
  `confidence` decimal(3, 2) NULL DEFAULT NULL COMMENT '置信度(0.00-1.00)',
  `parse_error_message` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '解析错误信息',
  `input_tokens` int NULL DEFAULT NULL COMMENT '输入Token数量',
  `output_tokens` int NULL DEFAULT NULL COMMENT '输出Token数量',
  `total_tokens` int NULL DEFAULT NULL COMMENT '总Token数量',
  `parse_time` bigint NULL DEFAULT NULL COMMENT '解析耗时(毫秒)',
  `function_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '执行的函数名称',
  `function_arguments` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '函数参数(JSON)',
  `execute_status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '执行状态(pending-待执行, success-成功, failed-失败)',
  `execute_result` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '执行结果(JSON)',
  `execute_error_message` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '执行错误信息',
  `affected_rows` int NULL DEFAULT NULL COMMENT '影响的记录数',
  `is_dangerous` tinyint(1) NULL DEFAULT 0 COMMENT '是否危险操作(0-否, 1-是)',
  `requires_confirmation` tinyint(1) NULL DEFAULT 0 COMMENT '是否需要确认(0-否, 1-是)',
  `user_confirmed` tinyint(1) NULL DEFAULT NULL COMMENT '用户是否确认(0-否, 1-是)',
  `idempotency_key` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '幂等性令牌(防止重复执行)',
  `execution_time` bigint NULL DEFAULT NULL COMMENT '执行耗时(毫秒)',
  `ip_address` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'IP地址',
  `user_agent` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '用户代理',
  `current_route` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '当前页面路由',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_idempotency_key`(`idempotency_key` ASC) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_create_time`(`create_time` ASC) USING BTREE,
  INDEX `idx_provider`(`provider` ASC) USING BTREE,
  INDEX `idx_model`(`model` ASC) USING BTREE,
  INDEX `idx_parse_success`(`parse_success` ASC) USING BTREE,
  INDEX `idx_execute_status`(`execute_status` ASC) USING BTREE,
  INDEX `idx_is_dangerous`(`is_dangerous` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'AI命令记录表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of ai_command_record
-- ----------------------------

