  `analy_instrument_circuit` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '回路数',
  `analy_instrument_supplier` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '供应商',
  `analy_instrument_prod_date` datetime NOT NULL COMMENT '生产日期',
  `analy_instrument_use_date` datetime NOT NULL COMMENT '投用日期',
  `analy_instrument_guarantee_date` datetime NOT NULL COMMENT '质保日期',
  `analy_instrument_maintain_flag` tinyint(1) NOT NULL COMMENT '是否质保期内(0/1)',
