-- ----------------------------
-- Table structure for explosion_proof_electric_equipment
-- ----------------------------
DROP TABLE IF EXISTS `explosion_proof_electric_equipment`;
CREATE TABLE `explosion_proof_electric_equipment`  (
  `id` bigint NOT NULL COMMENT '序号',
