-- ----------------------------
-- Table structure for interlock_bypass
-- ----------------------------
DROP TABLE IF EXISTS `interlock_bypass`;
CREATE TABLE `interlock_bypass`  (
  `id` bigint NOT NULL COMMENT '序号',
  `interlock_bypass_code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '旁路记录编号',
  `interlock_bypass_interlock_code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '关联联锁回路编号',
  `interlock_bypass_interlock_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '关联联锁名称',
  `interlock_bypass_reason` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '旁路 / 解除原因（检修 / 调试 / 工艺操作 / 故障处理等）',
  `interlock_bypass_start_time` date NOT NULL COMMENT '旁路 / 解除开始时间',
  `interlock_bypass_end_time` date NULL DEFAULT NULL COMMENT '旁路 / 解除结束时间',
  `interlock_bypass_duration` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '旁路时长（自动计算或手动填写）',
  `interlock_bypass_applicant` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '申请人',
  `interlock_bypass_approver` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '审批人',
  `interlock_bypass_operator` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '执行操作人',
  `interlock_bypass_risk_assessment` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '风险评估及控制措施',
  `interlock_bypass_monitor` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '旁路期间监控措施',
  `interlock_bypass_status` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '当前状态（进行中 / 已恢复 / 已取消）',
  `interlock_bypass_factory` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '所属工厂',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '联锁旁路/解除台账表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of interlock_bypass
-- ----------------------------

-- ----------------------------
-- Table structure for interlock_logic
-- ----------------------------
DROP TABLE IF EXISTS `interlock_logic`;
CREATE TABLE `interlock_logic`  (
  `id` bigint NOT NULL COMMENT '序号',
  `interlock_logic_code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '联锁逻辑编号',
  `interlock_logic_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '联锁名称',
  `interlock_logic_system` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '所属系统（DCS/SIS/ESD/PLC/GDS）',
  `interlock_logic_device` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '涉及设备 / 位号',
  `interlock_logic_condition` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '联锁触发条件',
  `interlock_logic_value` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '联锁设定值',
  `interlock_logic_action` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '联锁动作',
  `interlock_logic_level` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '联锁等级',
  `interlock_logic_status` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '投用状态（投用 / 旁路 / 停用）',
  `interlock_logic_area` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '所属装置 / 区域',
  `interlock_logic_design` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '设计人员',
  `interlock_logic_check` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '审核人员',
  `interlock_logic_approve` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '批准人员',
  `interlock_logic_bypass` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '旁路记录',
  `interlock_logic_factory` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '所属工厂',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '联锁逻辑台账表\r\n' ROW_FORMAT = DYNAMIC;

