  `se_compressor_rated_pressure` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '额定排气压力（MPa）',
  `se_compressor_rated_power` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '额定输入功率（kW）',
  `se_compressor_rated_speed` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '额定转速（r/min）',
