DROP TABLE IF EXISTS `se_safety_barrier`;
CREATE TABLE `se_safety_barrier`  (
  `id` bigint NOT NULL COMMENT '序号',
  `se_safety_barrier_code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '安全栅 / 隔离器编号',
  `se_safety_barrier_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '设备名称',
  `se_safety_barrier_type` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '设备类型（齐纳式安全栅 / 隔离式安全栅 / 信号隔离器 / 浪涌保护器）',
  `se_safety_barrier_spec` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '规格型号',
  `se_safety_barrier_input_signal` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '输入信号类型（4-20mA/0-10V / 热电阻 / 热电偶 / 开关量）',
  `se_safety_barrier_output_signal` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '输出信号类型',
