  `se_safety_barrier_connect_instru` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '关联仪表位号 / 名称',
  `se_safety_barrier_install_pos` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '安装位置（机柜号 / 防爆柜 / 现场接线箱 / 装置区域）',
  `se_safety_barrier_voltage` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '工作电压（24VDC/220VAC）',
  `se_safety_barrier_in_service` date NULL DEFAULT NULL COMMENT '投用日期',
  `se_safety_barrier_check_cycle` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '校验 / 巡检周期',
  `se_safety_barrier_last_check` date NULL DEFAULT NULL COMMENT '上次校验/巡检日期',
  `se_safety_barrier_next_check` date NULL DEFAULT NULL COMMENT '下次校验/巡检日期',
  `se_safety_barrier_fault_record` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '故障及异常记录',
  `se_safety_barrier_factory` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '所属工厂',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '安全栅 / 隔离器台账' ROW_FORMAT = DYNAMIC;

