  `se_safety_valve_check_cycle` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '校验周期',
  `se_safety_valve_last_check` date NULL DEFAULT NULL COMMENT '上次校验日期',
  `se_safety_valve_next_check` date NULL DEFAULT NULL COMMENT '下次校验日期',
  `se_safety_valve_check_result` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '校验结果',
