  `spec_eqp_vt_factory_no` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '出厂编号',
  `spec_eqp_vt_produce_date` date NOT NULL COMMENT '制造日期',
  `spec_eqp_vt_install_company` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '安装单位',
  `spec_eqp_vt_install_date` date NOT NULL COMMENT '安装日期',
  `spec_eqp_vt_acceptance_date` date NOT NULL COMMENT '验收日期',
  `spec_eqp_vt_usage_date` datetime NOT NULL COMMENT '投用日期',
  `spec_eqp_vt_license_no` int NOT NULL COMMENT '特种设备使用登记',
  `spec_eqp_vt_status` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '设备状态',
  `spec_eqp_vt_last_inspect_date` date NULL DEFAULT NULL COMMENT '上次检验日期',
  `spec_eqp_vt_next_inspect_date` date NULL DEFAULT NULL COMMENT '下次检验日期',
  `spec_eqp_vt_inspect_company` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '检验机构',
  `spec_eqp_vt_maintain_responsible` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '运维责任人',
  `spec_eqp_vt_maintain_record` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '最后一次维护记录',
  `spec_eqp_vt_accident_record` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '事故记录',
  `spec_eqp_vt_create_time` date NOT NULL COMMENT '创建时间',
  `spec_eqp_vt_update_time` date NOT NULL COMMENT '更新时间',
  `spec_eqp_vt_factory` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '所属工厂',
  `spec_eqp_vt_backup1` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '备用1',
  `spec_eqp_vt_backup2` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '备用2',
  `spec_eqp_vt_backup3` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '备用3',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '特种设备立罐台账' ROW_FORMAT = DYNAMIC;

