-- Records of sys_dict_item
-- ----------------------------

-- ----------------------------
-- Table structure for sys_instrument_fault
-- ----------------------------
DROP TABLE IF EXISTS `sys_instrument_fault`;
CREATE TABLE `sys_instrument_fault`  (
  `id` bigint NOT NULL COMMENT '序号',
  `sys_instrument_fault_type` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '故障类型',
  `sys_instrument_workstation_crash` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '工作站死机',
  `sys_instrument_workstation_slow` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '工作站反应缓慢',
  `sys_instrument_display_fault` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '显示器/键盘/鼠标故障',
  `sys_instrument_comm_fault` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '通讯故障/报警',
  `sys_instrument_param_error` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '检测/控制参数不准/错误',
  `sys_instrument_alarm_trend` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '报警/历史趋势故障',
  `sys_instrument_power_fault` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '电源故障/报警',
  `sys_instrument_controller_fault` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '控制器故障/报警',
  `sys_instrument_io_fault` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'I/O卡或端子板故障/报警',
  `sys_instrument_other` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '其他',
  `sys_instrument_total` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '合计',
  `sys_instrument_factory` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '所属工厂',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '系统仪表故障现象分类' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of sys_instrument_fault
-- ----------------------------

-- ----------------------------
-- Table structure for sys_instrument_fault_account
-- ----------------------------
DROP TABLE IF EXISTS `sys_instrument_fault_account`;
CREATE TABLE `sys_instrument_fault_account`  (
  `id` bigint NOT NULL COMMENT '序号',
  `sys_instrument_fault_account_code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '故障记录编号',
  `sys_instrument_fault_account_type` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '系统类型（DCS/SIS/PLC/GDS/ 工控网络 / UPS）',
  `sys_instrument_fault_account_phenomenon` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '故障现象（工作站死机 / 通讯故障 / 卡件报警等）',
  `sys_instrument_fault_account_location` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '故障部位（PC 主机 / 控制器 / I/O 卡 / 电源模块等）',
  `sys_instrument_fault_account_cause` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '故障原因（组态错误 / 失电 / 设备老化 / 信号干扰等）',
  `sys_instrument_fault_account_happen_time` date NOT NULL COMMENT '故障发生时间',
  `sys_instrument_fault_account_handle_time` date NULL DEFAULT NULL COMMENT '故障处理开始时间',
  `sys_instrument_fault_account_recover_time` date NULL DEFAULT NULL COMMENT '故障恢复时间',
  `sys_instrument_fault_account_handle_person` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '处理人员',
  `sys_instrument_fault_account_handle_method` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '处理方法（重启 / 更换卡件 / 重新组态 / 排除干扰等）',
  `sys_instrument_fault_account_impact` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '故障影响范围（单回路 / 整装置 / 联锁触发 / 无生产影响）',
  `sys_instrument_fault_account_loss` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '故障损失（经济损失 / 停车时长 / 产量影响）',
  `sys_instrument_fault_account_prevent` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '预防措施',
  `sys_instrument_fault_account_install_pos` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '故障设备安装位置 / 所属装置',
  `sys_instrument_fault_account_factory` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '所属工厂',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '系统类故障台账表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of sys_instrument_fault_account
-- ----------------------------

-- ----------------------------
-- Table structure for sys_instrument_fault_cause
-- ----------------------------
DROP TABLE IF EXISTS `sys_instrument_fault_cause`;
CREATE TABLE `sys_instrument_fault_cause`  (
  `id` bigint NOT NULL COMMENT '序号',
  `sys_instrument_fault_cause_type` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '故障类型',
  `sys_instrument_fault_cause_config` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '组态错误',
  `sys_instrument_fault_cause_power` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '失电/晃电',
  `sys_instrument_fault_cause_selection` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '选型/安装不当',
  `sys_instrument_fault_cause_environment` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '环境条件问题',
  `sys_instrument_fault_cause_aging` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '设备老化',
  `sys_instrument_fault_cause_quality` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '产品质量',
  `sys_instrument_fault_cause_interference` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '信号干扰',
  `sys_instrument_fault_cause_operation` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '工艺操作不当',
  `sys_instrument_fault_cause_maintain` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '维护不到位（失修）',
  `sys_instrument_fault_cause_tech` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '新技术认知不够',
  `sys_instrument_fault_cause_other` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '其他',
  `sys_instrument_fault_cause_total` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '合计',
  `sys_instrument_fault_cause_factory` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '所属工厂',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '系统仪表故障原因分类' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of sys_instrument_fault_cause
-- ----------------------------

-- ----------------------------
-- Table structure for sys_instrument_fault_location
-- ----------------------------
DROP TABLE IF EXISTS `sys_instrument_fault_location`;
CREATE TABLE `sys_instrument_fault_location`  (
  `id` bigint NOT NULL COMMENT '序号',
  `sys_instrument_fault_loc_type` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '故障类型',
  `sys_instrument_fault_loc_pc` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'PC主机/HM',
  `sys_instrument_fault_loc_display` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '显示器',
  `sys_instrument_fault_loc_keyboard` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '键盘鼠标',
  `sys_instrument_fault_loc_comm_part` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '通讯部件',
  `sys_instrument_fault_loc_comm_cable` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '通讯线缆',
  `sys_instrument_fault_loc_controller` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '控制器模块',
  `sys_instrument_fault_loc_io_card` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'I/O卡',
  `sys_instrument_fault_loc_io_terminal` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT 'I/O端子板',
  `sys_instrument_fault_loc_power` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '电源模块/供电回路',
  `sys_instrument_fault_loc_software` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '系统软件',
  `sys_instrument_fault_loc_other` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '其他',
  `sys_instrument_fault_loc_total` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '合计',
  `sys_instrument_fault_loc_factory` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '所属工厂',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '系统仪表故障部位分类' ROW_FORMAT = DYNAMIC;

