-- Records of sys_user_role
-- ----------------------------

-- ----------------------------
-- Table structure for thermo_valve
-- ----------------------------
DROP TABLE IF EXISTS `thermo_valve`;
CREATE TABLE `thermo_valve`  (
  `thermo_valve_sn` bigint NOT NULL COMMENT '序号',
  `thermo_valve_dev` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '装置',
  `thermo_valve_tag` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '阀门位号',
  `thermo_valve_type` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '阀门类型',
