  `status` tinyint NOT NULL DEFAULT 0 COMMENT '设备状态',
  `dv_type` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '设备类型',
